// R30 — Database helpers shared by store mutators.
//
// Two responsibilities:
//   1. Map the legacy in-memory user IDs (u-vp, u-mgr1, …) to the Postgres UUIDs
//      used in profiles.id (which are FK to auth.users.id). Same map is baked
//      into vite/migrations/r30_seed.sql so the FK references resolve.
//   2. Provide a fire-and-forget Supabase write wrapper so mutators stay
//      synchronous from React's POV (optimistic UI) while still persisting.

import { supabase, USE_SUPABASE } from './supabase.js';

// Stable UUIDs generated by vite/migrations/generate-seed.mjs (sha256-derived,
// so re-running the generator produces the same UUIDs on every machine).
// Source of truth: vite/migrations/uuid-map.json (kept identical to this map).
export const USER_UUID = {
  'u-vp':    '4c8e3a5b-7d2f-4b91-8a3c-1f6e9d8c7b5a',
  'u-mgr1':  'a1b2c3d4-e5f6-4789-9abc-def012345678',
  'u-mgr2':  'b2c3d4e5-f6a7-4890-bcde-f01234567890',
  'u-op1':   'c3d4e5f6-a7b8-4901-cdef-012345678901',
  'u-op2':   'd4e5f6a7-b8c9-4012-def0-123456789012',
  'u-pgm':   'e5f6a7b8-c9d0-4123-ef01-234567890123',
  'u-mat':   'f6a7b8c9-d0e1-4234-f012-345678901234',
  'u-coord': '07a8b9c0-d1e2-4345-8012-456789012345',
  'u-pm1':   '18b9c0d1-e2f3-4456-9123-567890123456',
  'u-pm2':   '29c0d1e2-f3a4-4567-a234-678901234567',
  'u-pm3':   '3ad1e2f3-a4b5-4678-b345-789012345678',
  'u-pm4':   '4be2f3a4-b5c6-4789-c456-890123456789',
  'u-pm5':   '5cf3a4b5-c6d7-489a-d567-90123456789a',
  'u-pm6':   '6da4b5c6-d7e8-49ab-e678-a12345678901',
  'u-pm7':   '7eb5c6d7-e8f9-4abc-f789-b23456789012',
};

export function userUuid(id) {
  if (!id) return null;
  if (USER_UUID[id]) return USER_UUID[id];
  // If we receive a real auth.users UUID (already in v4 form) pass it through.
  if (/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(id)) return id;
  return null;
}

// Reverse map: for incoming Supabase rows that carry profile UUIDs, find the
// legacy id the UI still uses (PEOPLE[].id). Falls through to UUID when no map.
const __REVERSE = Object.fromEntries(Object.entries(USER_UUID).map(([k, v]) => [v, k]));
export function legacyUserId(uuid) { return __REVERSE[uuid] || uuid; }

// Map R29 in-memory role names (e.g. 'Manager', 'Operations Manager') to the
// Postgres user_role enum values (snake_case).
export const ROLE_TO_ENUM = {
  'VP':                 'vp',
  'Manager':            'manager',
  'Operations Manager': 'operations_manager',
  'Program Manager':    'program_manager',
  'Project Manager':    'project_manager',
  'Material planning':  'material_planning',
  'Coordinator':        'coordinator',
  'Admin':              'admin',           // R30.19: full-access role
};
export const ENUM_TO_ROLE = Object.fromEntries(Object.entries(ROLE_TO_ENUM).map(([k, v]) => [v, k]));

// Fire-and-forget Supabase writer. The store mutator updates React state
// synchronously (optimistic), and this scheduled write persists in the
// background. On failure, we log to console + emit a window event the
// shell can toast on.
//   bg(fn, label) — fn returns a thenable; label is for error messages.
export function bg(fn, label) {
  if (!USE_SUPABASE) return;
  Promise.resolve().then(fn).then(({ error } = {}) => {
    if (error) {
      console.error(`[supabase ${label}]`, error);
      if (typeof window !== 'undefined') {
        window.dispatchEvent(new CustomEvent('supabase-error', { detail: { label, error } }));
      }
    }
  }).catch(err => {
    console.error(`[supabase ${label}] threw`, err);
  });
}

// Convenience: insert one row, fire-and-forget.
export function bgInsert(table, row, label = table) {
  bg(() => supabase.from(table).insert(row), `insert ${label}`);
}
// Convenience: update by id.
export function bgUpdate(table, id, patch, label = table) {
  bg(() => supabase.from(table).update(patch).eq('id', id), `update ${label}`);
}
// Convenience: delete by id.
export function bgDelete(table, id, label = table) {
  bg(() => supabase.from(table).delete().eq('id', id), `delete ${label}`);
}
// Convenience: delete by composite WHERE (used for photos table — no string PK).
export function bgDeleteWhere(table, where, label = table) {
  bg(() => {
    let q = supabase.from(table).delete();
    for (const [col, val] of Object.entries(where)) q = q.eq(col, val);
    return q;
  }, `delete ${label}`);
}
// Convenience: upsert (for app_settings).
export function bgUpsert(table, row, label = table) {
  bg(() => supabase.from(table).upsert(row), `upsert ${label}`);
}

// ── Translation helpers (in-memory row → DB row) ───────────────────────────
// Each helper picks ONLY the columns that exist in the live R30 schema and
// applies the necessary renames/enum conversions. Unknown patch keys are
// silently dropped (the in-memory store may carry extra UI-only state).

const PROJECT_STATUS_ENUM = {
  'On Track':'on_track','At Risk':'at_risk','Delayed':'delayed',
  'Complete':'completed','Completed':'completed','On Hold':'on_hold',
};
const TASK_PRIORITY_ENUM = { 'Low': 'low', 'Medium': 'medium', 'High': 'high', 'Urgent': 'urgent' };
const TASK_PRIORITY_DISPLAY = { 'low': 'Low', 'medium': 'Medium', 'high': 'High', 'urgent': 'Urgent' };
const TASK_STATUS_ENUM = {
  'Open':'todo','To Do':'todo','Todo':'todo',
  'In Progress':'in_progress','Blocked':'blocked','Done':'done',
};
const ESC_STATUS_ENUM = {
  'Open':'open','In Progress':'in_progress','Resolved':'resolved','Closed':'closed',
};
const URGENCY_ENUM = {
  'Low':'low','Medium':'medium','High':'high','Critical':'critical',
};
const DN_STATUS_ENUM = {
  'draft':'draft','received':'received','disputed':'disputed',
  'verified':'verified','rejected':'disputed',
};
const SCHOOL_REMARK_ENUM = {
  'On Schedule':'active','Ahead':'active','Active':'active',
  'Behind':'delayed','Blocked':'blocked','In Progress':'active',
};
const SCHOOL_REMARK_ENUM_DIRECT = {
  // allow callers to pass already-canonical values
  'active':'active','access_issue':'access_issue','delayed':'delayed','blocked':'blocked','excluded':'excluded',
};
function mapEnum(value, table, fallback) {
  if (value == null) return fallback;
  if (table[value]) return table[value];
  return fallback;
}

// Coords: legacy stores raw strings like "26.37 N, 49.99 E" or "26.37,49.99".
// Live schema expects "lat,lng" decimal text or NULL.
function normalizeCoords(raw) {
  if (raw == null) return null;
  const s = String(raw).trim();
  if (!s) return null;
  const cleaned = s.replace(/[NSEWnsew]/g, '').replace(/\s+/g, ' ').trim();
  const parts = cleaned.split(/[\s,]+/).filter(Boolean);
  if (parts.length !== 2) return null;
  const lat = parseFloat(parts[0]);
  const lng = parseFloat(parts[1]);
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return null;
  if (lat < -90 || lat > 90 || lng < -180 || lng > 180) return null;
  return `${lat},${lng}`;
}
function levelGenderConcat(level, gender) {
  const l = (level || '').trim(), g = (gender || '').trim();
  if (l && g) return `${l} / ${g}`;
  return l || g || null;
}

export function toDbProject(p) {
  return {
    id: p.id,
    name: p.name || 'Untitled program',
    region: p.region || '',
    city: p.city || null,
    contract_value: Number(p.value) || 0,
    currency: 'SAR',
    start_date: p.start || null,
    target_date: p.target || null,
    schools_count: p.sites || 0,
    assigned_pm_id: userUuid(p.pmId),
    project_type: 'school',
    status: mapEnum(p.status, PROJECT_STATUS_ENUM, 'on_track'),
    overall_progress: Number(p.progress) || 0,
  };
}
export function toDbProjectPatch(patch) {
  const out = {};
  if ('name' in patch)     out.name = patch.name;
  if ('region' in patch)   out.region = patch.region || '';
  if ('city' in patch)     out.city = patch.city || null;
  if ('value' in patch)    out.contract_value = Number(patch.value) || 0;
  if ('start' in patch)    out.start_date = patch.start || null;
  if ('target' in patch)   out.target_date = patch.target || null;
  if ('sites' in patch)    out.schools_count = patch.sites || 0;
  if ('pmId' in patch)     out.assigned_pm_id = userUuid(patch.pmId);
  if ('status' in patch)   out.status = mapEnum(patch.status, PROJECT_STATUS_ENUM, 'on_track');
  if ('progress' in patch) out.overall_progress = Number(patch.progress) || 0;
  return out;
}

export function toDbProfile(u) {
  const regions = Array.isArray(u.region) ? u.region : (u.region ? [u.region] : []);
  return {
    id: userUuid(u.id),
    full_name: u.name,
    email: u.email,
    role: ROLE_TO_ENUM[u.role] || null,
    mobile: u.mobile || null,
    default_regions: regions,
    archived: !!u.archived,
  };
}
export function toDbProfilePatch(patch) {
  const out = {};
  if ('name' in patch)     out.full_name = patch.name;
  if ('email' in patch)    out.email = patch.email;
  if ('role' in patch)     out.role = ROLE_TO_ENUM[patch.role] || null;
  if ('mobile' in patch)   out.mobile = patch.mobile || null;
  if ('region' in patch)   out.default_regions = Array.isArray(patch.region) ? patch.region : (patch.region ? [patch.region] : []);
  if ('archived' in patch) out.archived = !!patch.archived;
  return out;
}

export function toDbTask(t) {
  return {
    id: t.id,
    title: t.title || 'Untitled task',
    description: t.description || '',
    project_id: t.projectId || null,
    school_id: t.schoolId || null,
    assigned_to_id: userUuid(t.assigneeId),
    created_by_id: userUuid(t.createdById),
    status: mapEnum(t.status, TASK_STATUS_ENUM, 'todo'),
    due_date: t.due || null,
    priority: mapEnum(t.priority, TASK_PRIORITY_ENUM, 'medium'),
    created_at: t.createdAt ? new Date(t.createdAt).toISOString() : new Date().toISOString(),
  };
}
export function toDbTaskPatch(patch) {
  const out = {};
  if ('title' in patch)       out.title = patch.title;
  if ('description' in patch) out.description = patch.description || '';
  if ('projectId' in patch)   out.project_id = patch.projectId || null;
  if ('schoolId' in patch)    out.school_id = patch.schoolId || null;
  if ('assigneeId' in patch)  out.assigned_to_id = userUuid(patch.assigneeId);
  if ('status' in patch)      out.status = mapEnum(patch.status, TASK_STATUS_ENUM, 'todo');
  if ('due' in patch)         out.due_date = patch.due || null;
  if ('priority' in patch)    out.priority = mapEnum(patch.priority, TASK_PRIORITY_ENUM, 'medium');
  if (patch.status === 'Done' && !('completed_at' in out)) out.completed_at = new Date().toISOString();
  return out;
}

export function toDbSchool(s) {
  return {
    id: s.id,
    project_id: s.projectId,
    name_en: s.nameEn || null,
    name_ar: s.nameAr || null,
    city: s.city || null,
    region: s.region || null,
    level_gender: levelGenderConcat(s.level, s.gender),
    sec_meter: s.meter || null,
    account_no: s.account || null,
    contractor_name: s.contractor || null,
    coords: normalizeCoords(s.coords),
    remark: mapEnum(s.remark || s.status, { ...SCHOOL_REMARK_ENUM_DIRECT, ...SCHOOL_REMARK_ENUM }, 'active'),
    stages: s.stages || {},
  };
}
export function toDbSchoolPatch(patch) {
  const out = {};
  if ('projectId' in patch)   out.project_id = patch.projectId;
  if ('nameEn' in patch)      out.name_en = patch.nameEn || null;
  if ('nameAr' in patch)      out.name_ar = patch.nameAr || null;
  if ('city' in patch)        out.city = patch.city || null;
  if ('region' in patch)      out.region = patch.region || null;
  if ('level' in patch || 'gender' in patch) out.level_gender = levelGenderConcat(patch.level, patch.gender);
  if ('meter' in patch)       out.sec_meter = patch.meter || null;
  if ('account' in patch)     out.account_no = patch.account || null;
  if ('contractor' in patch)  out.contractor_name = patch.contractor || null;
  if ('coords' in patch)      out.coords = normalizeCoords(patch.coords);
  if ('remark' in patch)      out.remark = mapEnum(patch.remark, { ...SCHOOL_REMARK_ENUM_DIRECT, ...SCHOOL_REMARK_ENUM }, 'active');
  if ('stages' in patch)      out.stages = patch.stages || {};
  return out;
}

export function toDbContractor(c) {
  const regions = c.region ? [c.region] : [];
  const scores = [c.schedule, c.quality, c.hse, c.docs].filter(v => typeof v === 'number');
  const kpiScore = scores.length ? Math.round((scores.reduce((a,b)=>a+b,0) / scores.length) * 10) / 10 : 0;
  return {
    id: c.id,
    company_name: c.name,
    category: c.category || null,
    cr_number: c.cr || null,
    license_number: c.license || null,
    contact_person: c.contact || null,
    phone: c.phone || null,
    email: c.email || null,
    default_regions: regions,
    kpi_score: kpiScore,
    archived: !!c.archived,
  };
}
export function toDbContractorPatch(patch) {
  const out = {};
  if ('name' in patch)     out.company_name = patch.name;
  if ('category' in patch) out.category = patch.category || null;
  if ('cr' in patch)       out.cr_number = patch.cr || null;
  if ('license' in patch)  out.license_number = patch.license || null;
  if ('contact' in patch)  out.contact_person = patch.contact || null;
  if ('phone' in patch)    out.phone = patch.phone || null;
  if ('email' in patch)    out.email = patch.email || null;
  if ('region' in patch)   out.default_regions = patch.region ? [patch.region] : [];
  if ('archived' in patch) out.archived = !!patch.archived;
  return out;
}

export function toDbDeliveryNote(n) {
  return {
    id: n.id,
    project_id: n.projectId || null,
    school_id: n.schoolId || null,
    stage_key: n.stageKey || null,
    delivery_date: n.deliveryDate || null,
    supplier: n.supplier || null,
    contractor: n.contractor || null,
    received_by: n.receivedBy || null,
    signature_path: n.signatureDataUrl || n.signaturePath || null,
    notes: n.notes || null,
    status: mapEnum(n.status, DN_STATUS_ENUM, 'draft'),
    created_by_id: userUuid(n.createdBy),
    created_at: n.createdAt ? new Date(n.createdAt).toISOString() : new Date().toISOString(),
  };
}
export function toDbDeliveryNoteItems(noteId, items) {
  return (items || []).map((it, idx) => ({
    delivery_note_id: noteId,
    description: it.description || null,
    quantity: (it.quantity == null || it.quantity === '') ? null : Number(it.quantity),
    unit: it.unit || null,
    position: idx,
  }));
}
export function toDbDeliveryNotePatch(patch) {
  const out = { updated_at: new Date().toISOString() };
  if ('projectId' in patch)    out.project_id = patch.projectId || null;
  if ('schoolId' in patch)     out.school_id = patch.schoolId || null;
  if ('stageKey' in patch)     out.stage_key = patch.stageKey || null;
  if ('deliveryDate' in patch) out.delivery_date = patch.deliveryDate || null;
  if ('supplier' in patch)     out.supplier = patch.supplier || null;
  if ('contractor' in patch)   out.contractor = patch.contractor || null;
  if ('receivedBy' in patch)   out.received_by = patch.receivedBy || null;
  if ('signatureDataUrl' in patch) out.signature_path = patch.signatureDataUrl || null;
  if ('notes' in patch)        out.notes = patch.notes || null;
  if ('status' in patch)       out.status = mapEnum(patch.status, DN_STATUS_ENUM, 'draft');
  return out;
}

export function toDbEscalation(e) {
  return {
    id: e.id,
    title: e.title || '',
    description: e.reason || e.description || null,
    project_id: e.projectId || null,
    school_id: e.schoolId || null,
    status: mapEnum(e.status, ESC_STATUS_ENUM, 'open'),
    urgency: mapEnum(e.urgency, URGENCY_ENUM, 'medium'),
    raised_by_id: userUuid(e.fromUserId),
    raised_to_role: ROLE_TO_ENUM[e.toRole] || null,
    currently_with_id: userUuid(e.currentlyWith || e.toUserId),
    assigned_to_id: userUuid(e.currentlyWith || e.toUserId),
    days_open: e.daysOpen || 0,
    created_at: e.opened ? new Date(e.opened).toISOString() : new Date().toISOString(),
    resolved_at: e.resolvedDate ? new Date(e.resolvedDate).toISOString() : null,
    updated_at: new Date().toISOString(),
  };
}

export function toDbAudit(entry) {
  return {
    entity_type: entry.entityType || null,
    entity_id: entry.entityId || null,
    action: entry.action || null,
    user_id: userUuid(entry.actorId),
    user_name: entry.actorName || null,
    user_role: ROLE_TO_ENUM[entry.actorRole] || entry.actorRole || null,
    payload: { before: entry.before ?? null, after: entry.after ?? null, entityLabel: entry.entityLabel ?? null },
    summary: entry.summary || null,
    created_at: entry.timestamp ? new Date(entry.timestamp).toISOString() : new Date().toISOString(),
  };
}

if (typeof window !== 'undefined') {
  Object.assign(window, {
    USER_UUID, userUuid, legacyUserId, ROLE_TO_ENUM, ENUM_TO_ROLE,
    bg, bgInsert, bgUpdate, bgDelete, bgDeleteWhere, bgUpsert,
    toDbProject, toDbProjectPatch,
    toDbProfile, toDbProfilePatch,
    toDbTask, toDbTaskPatch,
    toDbSchool, toDbSchoolPatch,
    toDbContractor, toDbContractorPatch,
    toDbDeliveryNote, toDbDeliveryNoteItems, toDbDeliveryNotePatch,
    toDbEscalation,
    toDbAudit,
  });
}

// ─── R30.2 — Read side ─────────────────────────────────────────────────────
// fromDb* translators mirror the toDb* helpers above. They map snake_case
// Supabase rows back to the camelCase / nested shape the JSX consumes
// (legacy R29 store shape). Each helper accepts a single row and returns
// the in-memory object; pass arrays through `rows.map(fromDb*)`.
//
// Enum-display reverse maps (toDb maps display → enum; fromDb maps enum → display).

const PROJECT_STATUS_DISPLAY = {
  on_track: 'On Track', at_risk: 'At Risk', delayed: 'Delayed',
  completed: 'Complete', on_hold: 'On Hold',
};
const TASK_STATUS_DISPLAY = {
  todo: 'Open', in_progress: 'In Progress', blocked: 'Blocked', done: 'Done',
};
const ESC_STATUS_DISPLAY = {
  open: 'Open', in_progress: 'In Progress', resolved: 'Resolved', closed: 'Closed',
};
const URGENCY_DISPLAY = {
  low: 'Low', medium: 'Medium', high: 'High', critical: 'Critical',
};
const SCHOOL_REMARK_DISPLAY = {
  active: 'Active', access_issue: 'Access Issue', delayed: 'Delayed',
  blocked: 'Blocked', excluded: 'Excluded',
};

function computeInitials(fullName) {
  return (fullName || '').trim().split(/\s+/).map(s => s[0] || '').slice(0, 2).join('').toUpperCase();
}

export function fromDbProfile(row) {
  // DB row: { id uuid, full_name, email, role enum, mobile, default_regions text[],
  //           archived, avatar_url, created_at, updated_at }
  // UI shape: { id, name, email, role(display), region(first), mobile, avatarUrl,
  //             archived, active, initials, [projectIds — populated by boot] }
  if (!row) return null;
  const fullName = row.full_name || '';
  return {
    id: legacyUserId(row.id),
    name: fullName,
    email: row.email || '',
    role: ENUM_TO_ROLE[row.role] || row.role || '',
    region: (Array.isArray(row.default_regions) && row.default_regions[0]) || '',
    mobile: row.mobile || '',
    avatarUrl: row.avatar_url || null,
    archived: !!row.archived,
    active: !row.archived,
    initials: computeInitials(fullName),
  };
}

export function fromDbProject(row) {
  // DB row: { id text, name, name_ar, region, city, contract_value numeric,
  //           currency, start_date, target_date, schools_count, assigned_pm_id uuid,
  //           project_type enum, status enum, overall_progress, cover_path, description }
  // UI shape: { id, name, nameAr, region, city, value, start, target, sites,
  //             pmId, type(display), status(display), progress }
  if (!row) return null;
  return {
    id: row.id,
    name: row.name || '',
    nameAr: row.name_ar || '',
    region: row.region || '',
    city: row.city || '',
    value: Number(row.contract_value) || 0,
    start: row.start_date || null,
    target: row.target_date || null,
    sites: row.schools_count || 0,
    pmId: legacyUserId(row.assigned_pm_id),
    type: row.project_type === 'standalone' ? 'Standalone' : 'School Program',
    status: PROJECT_STATUS_DISPLAY[row.status] || row.status || 'On Track',
    progress: row.overall_progress || 0,
  };
}

export function fromDbSchool(row) {
  // DB row: { id text, project_id, name_en, name_ar, city, region, level_gender,
  //           sec_meter, account_no, contractor_name, coords, current_stage_key,
  //           remark enum, stages jsonb }
  // UI shape: { id, code, projectId, name (computed), nameEn, nameAr, level, gender,
  //             city, region, coords, meter, account, contractor, remark(display),
  //             status(recomputed from stages), stages[], rawStages{}, ... + R29 fields }
  if (!row) return null;
  const lgParts = (row.level_gender || '').split(' / ').map(s => s.trim());
  const level = lgParts[0] || '';
  const gender = lgParts[1] || '';
  const stages = Array.isArray(row.stages) ? row.stages : [];
  const rawStages = {};
  for (const st of stages) {
    if (st && st.key) rawStages[st.key] = st.statusId || (st.done ? 'done' : 'not-started');
  }
  const doneCount = stages.filter(st => st && st.done).length;
  const status = (stages.length > 0 && doneCount === stages.length) ? 'Completed'
               : doneCount > 0 ? 'In Progress'
               : 'Not Started';
  return {
    id: row.id,
    code: row.id,
    projectId: row.project_id || null,
    name: row.name_en || row.name_ar || row.id,
    nameEn: row.name_en || '',
    nameAr: row.name_ar || '',
    level: level || 'Primary',
    gender: gender || 'Boys',
    region: row.region || '',
    city: row.city || '',
    coords: row.coords || '',
    meter: row.sec_meter || '',
    account: row.account_no || '',
    contractor: row.contractor_name || '',
    remark: SCHOOL_REMARK_DISPLAY[row.remark] || 'Active',
    status,
    stages,
    rawStages,
    address: (row.city || '') + (row.region ? ', ' + row.region : ''),
    type: level || 'Primary',
    kw: 100,
    survey: null,
    installStart: null,
    issues: [],
    photos: {},
    photosList: [],
    deliveryNotes: [],
    materialUsage: [],
    lastUpdate: { by: null, when: null },
  };
}

export function fromDbContractor(row) {
  // DB row: { id, company_name, category, cr_number, license_number, contact_person,
  //           phone, email, default_regions text[], kpi_score numeric, archived }
  // UI shape: { id, name, region(first), category, cr, license, contact, phone, email,
  //             archived, activeSites, schedule, quality, hse, docs, projects, trend }
  // Note: schedule/quality/hse/docs/projects/trend not in DB — synthesize from kpi_score
  // so the contractors page doesn't blow up. R30.3 may introduce a richer contractor schema.
  if (!row) return null;
  const score = Math.round(row.kpi_score || 0);
  return {
    id: row.id,
    name: row.company_name || '',
    region: (Array.isArray(row.default_regions) && row.default_regions[0]) || '',
    category: row.category || 'EPC',
    cr: row.cr_number || '',
    license: row.license_number || '',
    contact: row.contact_person || '',
    phone: row.phone || '',
    email: row.email || '',
    archived: !!row.archived,
    activeSites: 0,
    schedule: score,
    quality: score,
    hse: score,
    docs: score,
    projects: [],
    trend: [score, score, score, score],
  };
}

export function fromDbTaskMessage(row) {
  // DB row: { id bigserial, task_id, author_id uuid, body, created_at }
  // UI shape: { id, userId, text, when }
  if (!row) return null;
  return {
    id: 'tm' + row.id,
    userId: legacyUserId(row.author_id),
    text: row.body || '',
    when: row.created_at || '',
  };
}
export function fromDbTask(row) {
  // DB row: { id text, title, description, project_id, school_id, assigned_to_id uuid,
  //           created_by_id uuid, status enum, due_date, created_at, completed_at,
  //           task_messages: [...]  (embed via PostgREST select) }
  // UI shape: { id, title, description, assigneeId, createdById, createdAt, due,
  //             priority, status(display), projectId, schoolId, stageIndex, messages[] }
  if (!row) return null;
  const messages = Array.isArray(row.task_messages) ? row.task_messages.map(fromDbTaskMessage) : [];
  messages.sort((a, b) => new Date(a.when) - new Date(b.when));
  return {
    id: row.id,
    title: row.title || '',
    description: row.description || '',
    assigneeId: legacyUserId(row.assigned_to_id),
    createdById: legacyUserId(row.created_by_id),
    createdAt: row.created_at ? String(row.created_at).slice(0, 10) : '',
    due: row.due_date || '',
    priority: TASK_PRIORITY_DISPLAY[row.priority] || 'Medium',
    status: TASK_STATUS_DISPLAY[row.status] || 'Open',
    projectId: row.project_id || null,
    schoolId: row.school_id || null,
    stageIndex: null,
    messages,
  };
}

export function fromDbEscalationHistory(row) {
  // DB row: { id bigserial, escalation_id, from_user_id, to_user_id, action, note, created_at }
  // UI shape: { who, when, action, note }
  if (!row) return null;
  return {
    who: legacyUserId(row.from_user_id),
    when: row.created_at ? String(row.created_at).slice(0, 10) : '',
    action: row.action || '',
    note: row.note || '',
  };
}
export function fromDbEscalation(row) {
  // DB row: { id text, title, description, project_id, school_id, status enum,
  //           urgency enum, raised_by_id, raised_to_role enum, currently_with_id,
  //           assigned_to_id, days_open, created_at, resolved_at,
  //           escalation_history: [...] }
  // UI shape: { id, title, reason, urgency(display), status(display), projectId,
  //             schoolId, taskId(null), fromUserId, currentlyWith, toUserId, toRole,
  //             opened, daysOpen, resolvedDate, chain[], history[] }
  if (!row) return null;
  const history = Array.isArray(row.escalation_history) ? row.escalation_history.map(fromDbEscalationHistory) : [];
  history.sort((a, b) => new Date(a.when) - new Date(b.when));
  return {
    id: row.id,
    title: row.title || '',
    reason: row.description || '',
    urgency: URGENCY_DISPLAY[row.urgency] || 'Medium',
    status: ESC_STATUS_DISPLAY[row.status] || 'Open',
    projectId: row.project_id || null,
    schoolId: row.school_id || null,
    taskId: null,
    fromUserId: legacyUserId(row.raised_by_id),
    currentlyWith: legacyUserId(row.currently_with_id),
    toUserId: legacyUserId(row.assigned_to_id),
    toRole: ENUM_TO_ROLE[row.raised_to_role] || row.raised_to_role || '',
    opened: row.created_at ? String(row.created_at).slice(0, 10) : '',
    daysOpen: row.days_open || 0,
    resolvedDate: row.resolved_at ? String(row.resolved_at).slice(0, 10) : null,
    chain: [],
    history,
  };
}

export function fromDbDeliveryNoteItem(row) {
  // DB row: { id bigserial, delivery_note_id, description, quantity numeric, unit, position }
  // UI shape: { description, quantity (string), unit }
  if (!row) return null;
  return {
    description: row.description || '',
    quantity: row.quantity == null ? '' : String(row.quantity),
    unit: row.unit || '',
  };
}
export function fromDbDeliveryNote(row) {
  // DB row: { id text, project_id, school_id, stage_key, delivery_date, supplier,
  //           contractor, received_by, signature_path, notes, status enum,
  //           created_by_id, created_at, delivery_note_items: [...] }
  // UI shape: { id, projectId, schoolId, stageKey, deliveryDate, supplier, contractor,
  //             receivedBy, signatureDataUrl, items[], photos[], notes, status, createdAt, createdBy }
  if (!row) return null;
  const items = Array.isArray(row.delivery_note_items)
    ? row.delivery_note_items.slice().sort((a, b) => (a.position || 0) - (b.position || 0)).map(fromDbDeliveryNoteItem)
    : [];
  return {
    id: row.id,
    projectId: row.project_id || null,
    schoolId: row.school_id || null,
    stageKey: row.stage_key || '',
    deliveryDate: row.delivery_date || '',
    supplier: row.supplier || '',
    contractor: row.contractor || '',
    receivedBy: row.received_by || '',
    signatureDataUrl: row.signature_path || null,
    items: items.length ? items : [{ description: '', quantity: '', unit: '' }],
    photos: [],
    notes: row.notes || '',
    status: row.status || 'received',
    createdAt: row.created_at || '',
    createdBy: legacyUserId(row.created_by_id),
  };
}

export function fromDbAuditLog(row) {
  // DB row: { id bigserial, entity_type, entity_id, action, user_id, user_name,
  //           user_role, payload jsonb {before,after,entityLabel}, summary, created_at }
  // UI shape: { id, timestamp, actorId, actorName, actorRole, action, entityType,
  //             entityId, entityLabel, before, after, summary }
  if (!row) return null;
  const payload = (row.payload && typeof row.payload === 'object') ? row.payload : {};
  return {
    id: 'au-' + row.id,
    timestamp: row.created_at || '',
    actorId: legacyUserId(row.user_id),
    actorName: row.user_name || '',
    actorRole: ENUM_TO_ROLE[row.user_role] || row.user_role || '',
    action: row.action || '',
    entityType: row.entity_type || '',
    entityId: row.entity_id || '',
    entityLabel: payload.entityLabel || '',
    before: payload.before ?? null,
    after: payload.after ?? null,
    summary: row.summary || '',
  };
}

// ─── Loaders (Item 2) ──────────────────────────────────────────────────────
// All return [] (or null for single-row) on error and log to console.warn.
// They are async but called from a non-React context (boot orchestrator);
// React just receives the resolved data via store setters.

async function _safeFetch(label, fn) {
  if (!USE_SUPABASE || !supabase) return null;
  try {
    const res = await fn();
    if (res && res.error) { console.warn(`[R30.2 fetch ${label}]`, res.error); return null; }
    return res;
  } catch (e) {
    console.warn(`[R30.2 fetch ${label}]`, e);
    return null;
  }
}

export async function bgFetchProfiles() {
  const res = await _safeFetch('profiles', () => supabase.from('profiles').select('*'));
  return (res && res.data) || [];
}

export async function bgFetchProjects() {
  const res = await _safeFetch('projects', () => supabase.from('projects').select('*'));
  return (res && res.data) || [];
}

// Schools: 2,600 rows ≈ 5 MB. Three paginated range() calls in parallel,
// each within Supabase's default 1 MB response limit (Q4 / option B).
export async function bgFetchSchools() {
  if (!USE_SUPABASE || !supabase) return [];
  try {
    const ranges = [[0, 999], [1000, 1999], [2000, 2999]];
    const results = await Promise.all(ranges.map(([from, to]) =>
      supabase.from('schools').select('*').range(from, to)
    ));
    const rows = [];
    for (const r of results) {
      if (r.error) console.warn('[R30.2 fetch schools page]', r.error);
      else if (r.data) rows.push(...r.data);
    }
    return rows;
  } catch (e) { console.warn('[R30.2 fetch schools]', e); return []; }
}

